            <input
              class="field-input"
              type="number"
              v-model="deliveryPhone"
              placeholder="请输入联系电话"
              maxlength="11"
            />
          </view>
        </view>

        <view class="modal-section">
          <text class="section-caption">订单备注</text>
          <view class="field-card">
            <textarea
