<script>
export default {
  data() {
    return {
      allCategory: { id: 0, name: '全部商品' },
      currentCategory: { id: 0, name: '全部商品' },
      cartExpanded: false,
      purchaseTypes: [],
      purchases: [],
      cartItems: [],
      deliveryAddress: '',
      deliveryPhone: '',
      showOrderModal: false,
      orderRemark: ''
    }
  },

  computed: {
    filteredProducts() {
      if (this.currentCategory.id === 0) {
        return this.purchases;
      }
      return this.purchases.filter(product => product.purchasesType.id === this.currentCategory.id);
    },

    totalPrice() {
      return this.cartItems.reduce((total, item) => total + item.price * item.quantity, 0);
    }
  },

  onLoad() {
    this.loadUserInfo();
  },

  onShow() {
    this.loadUserInfo();
    this.getPurchasesTypes();
    this.getPurchases();
  },

  methods: {
    async getPurchasesTypes() {
      const res = await this.$myRequest({
        url: '/user/ordersCtl/purchasesTypes',
        method: 'GET'
      });
      this.purchaseTypes = res.data.data;
    },

    async getPurchases() {
      const res = await this.$myRequest({
        url: '/user/ordersCtl/purchasesList',
        method: 'GET'
      });
      this.purchases = res.data.data;
    },

    loadUserInfo() {
      this.deliveryAddress = uni.getStorageSync('userAddress') || '';
      this.deliveryPhone = uni.getStorageSync('userPhone') || '';
    },

    selectCategory(category) {
      this.currentCategory = category;
    },

    selectProduct(product) {
      uni.showModal({
        title: product.name,
        content: `${this.getProductDesc(product)}\n价格: ¥${Number(product.price).toFixed(2)}/件`,
        confirmText: '加入购物车',
        success: (res) => {
          if (res.confirm) {
            this.addToCart(product);
          }
        }
      });
    },

    getProductDesc(product) {
      const categoryMap = {
        1: '日常生活必需品',
        2: '优质食品调料',
        3: '新鲜蔬菜水果',
        4: '健康保健药品',
        5: '实用家居用品'
      };
      return categoryMap[product.purchasesType && product.purchasesType.id] || '优质商品';
    },

    toggleCart() {
      this.cartExpanded = !this.cartExpanded;
    },

    addToCart(product) {
      const existingItem = this.cartItems.find(item => item.id === product.id);
      if (existingItem) {
        existingItem.quantity += 1;
      } else {
        this.cartItems.push({
          id: product.id,
          name: product.name,
          price: product.price,
          quantity: 1
        });
        this.cartExpanded = true;
      }

      uni.showToast({
        title: '已添加到购物车',
        icon: 'success'
      });
    },

    removeCartItem(item) {
      this.cartItems = this.cartItems.filter(cartItem => cartItem.id !== item.id);
    },

    placeOrder() {
      if (this.cartItems.length === 0) {
        uni.showToast({
          title: '购物车为空',
          icon: 'none'
        });
        return;
      }
      this.showOrderModal = true;
    },

    hideOrderModal() {
      this.showOrderModal = false;
      this.orderRemark = '';
    },

    async confirmOrder() {
      await this.submitOrder();
    },

    editDeliveryInfo() {
      uni.navigateTo({
        url: '/pages/userInfo/userInfo'
      });
    },

    async submitOrder() {
      try {
        uni.showLoading({
          title: '下单中...'
        });

        const userId = uni.getStorageSync('userId');
        if (!userId) {
          uni.hideLoading();
          uni.showToast({
            title: '请先登录',
            icon: 'none'
          });
          return;
        }

        if (!this.deliveryAddress || !this.deliveryPhone) {
          uni.hideLoading();
          uni.showModal({
            title: '配送信息不完整',
            content: '请先设置配送地址和联系电话',
            confirmText: '去设置',
            success: (res) => {
              if (res.confirm) {
                uni.navigateTo({
                  url: '/pages/userInfo/userInfo'
                });
              }
            }
          });
          return;
        }

        const orderData = {
          userId: parseInt(userId),
          communityId: uni.getStorageSync('communityId'),
          amount: this.totalPrice,
          deliveryAddress: this.deliveryAddress,
          deliveryPhone: this.deliveryPhone,
          remark: this.orderRemark,
          orderStatus: 0,
          typeid: 2,
          orderPurchasesItems: this.cartItems.map(item => ({
            purchasesId: item.id,
            quantity: item.quantity
          }))
        };

        const res = await this.$myRequest({
          url: '/user/ordersCtl/createOrderPurchases',
          method: 'POST',
          data: orderData
        });

        uni.hideLoading();

        if (res.data.code === 200) {
          uni.showToast({
            title: '下单成功',
            icon: 'success'
          });
          this.cartItems = [];
          this.cartExpanded = false;
          this.hideOrderModal();
        } else {
          uni.showToast({
            title: res.data.message || '下单失败',
            icon: 'none'
          });
        }
      } catch (error) {
        uni.hideLoading();
        console.error('下单失败:', error);
        uni.showToast({
          title: '网络错误，请重试',
          icon: 'none'
        });
      }
    }
  }
}
